-- Seeds professional Arabic translations for the current live rows in
-- services/sectors/case_studies/insights, keyed by slug. Only fills the
-- *_ar columns added in 20260708130000_add_arabic_content_columns.sql —
-- English columns are untouched. Safe to re-run (idempotent per slug).

update public.services set title_ar = 'الوصول إلى الشبكة المحلية والشركاء', description_ar = 'تعريفات مباشرة بأصحاب المصلحة والشركاء والموردين والجهات الرسمية العراقية الموثوقة — لتعرفوا من تقابلون وكيف تتحركون.', body_ar = '["دخول العراق دون شبكة محلية موثوقة يعني التخمين في من تثقون به وضياع الوقت في طرق مسدودة. تربطكم STRATIQ Access مباشرة بشركاء وموردين وجهات اتصال ميدانية عراقية موثوقة، ذات صلة بقطاعكم وأهدافكم.", "نساعدكم على فهم الواقع العملي — من هم أصحاب المصلحة المناسبون، وكيف تُتخذ القرارات فعليًا، وكيف تتنقلون بأمان وكفاءة بين الاجتماعات والمواقع والمكاتب."]'::jsonb, highlights_ar = '[{"title": "تعريفات موثوقة", "description": "وصول مباشر إلى أصحاب المصلحة والموردين والجهات الرسمية ذات الصلة بقطاعكم."}, {"title": "إرشاد محلي", "description": "توجيه عملي حول من تقابلون وكيف تسير الأعمال فعليًا في العراق."}, {"title": "وصول مستمر", "description": "نقطة اتصال محلية دائمة لفريقكم، لا مجرد تعريف لمرة واحدة."}]'::jsonb where slug = 'local-network-partner-access';
update public.services set title_ar = 'الإقامة الآمنة', description_ar = 'فنادق موثوقة، وسكن آمن، ودور ضيافة، وإقامة طويلة الأمد للوفود والمهندسين وفرق المشاريع.', body_ar = '["مكان إقامة فريقكم لا يقل أهمية عن مكان عملهم. نرتب فنادق موثوقة وسكنًا آمنًا وإقامة طويلة الأمد تتناسب مع دور فريقكم ومدة إقامته ومتطلباته الأمنية.", "من زيارة تنفيذي واحد إلى فريق مشروع متناوب، ندير الحجوزات والمعايير واللوجستيات، فتكون الإقامة أمرًا واحدًا أقل للتنسيق من الخارج."]'::jsonb, highlights_ar = '[{"title": "عقارات مدقَّقة", "description": "فنادق وسكن تم تقييمها من حيث السلامة والخدمة والموثوقية."}, {"title": "إقامة قصيرة وطويلة الأمد", "description": "من الزيارات الفردية إلى الإقامة طويلة الأمد لمشاريعكم."}, {"title": "جاهزية استقبال الوفود", "description": "حجوزات جماعية ولوجستيات منسّقة للوفود الكاملة."}]'::jsonb where slug = 'secure-accommodation';
update public.services set title_ar = 'التنسيق الأمني الخاص', description_ar = 'التنسيق مع مزوّدي الأمن الخاص المرخّصين لضمان التنقل الآمن، وزيارات المواقع، وسلامة الوفود.', body_ar = '["العمل بأمان في العراق يتطلب التخطيط لا الارتجال. تنسّق STRATIQ Access مع مزوّدي الأمن الخاص المرخّصين للتخطيط لتنقل آمن، وحماية زيارات المواقع، ودعم سلامة الوفود.", "يتم كل تنسيق أمني عبر مزوّدين محليين مرخّصين وفقًا للقوانين العراقية المعمول بها ومتطلبات الجهات المختصة — نحن نتولى التنسيق، لا التنفيذ الأمني ذاته."]'::jsonb, highlights_ar = '[{"title": "تخطيط التنقل الآمن", "description": "مسارات وتوقيتات وبروتوكولات مخطَّطة حول جدول أعمالكم."}, {"title": "حماية زيارات المواقع", "description": "تغطية منسّقة لزيارات المواقع والتفتيش الميداني."}, {"title": "سلامة الوفود", "description": "دعم تخطيط السلامة للزيارات التنفيذية والجماعية."}]'::jsonb where slug = 'private-security-coordination';
update public.services set title_ar = 'النقل الداخلي', description_ar = 'نقل من وإلى المطار، وسيارات كبار الشخصيات، ونقل الأعمال، ومركبات ميدانية بسائقين للتنقل بين المدن.', body_ar = '["النقل الموثوق هو العمود الفقري لأي زيارة أو مشروع في العراق. نرتب الاستقبال والتوصيل من المطار، وسيارات كبار الشخصيات، ونقل الأعمال، ومركبات ميدانية مع سائقين ذوي خبرة.", "سواء كان الأمر نقلاً تنفيذيًا واحدًا أو قافلة متعددة المركبات لفريق مشروع، ننسّق تنقلاً آمنًا وفي الوقت المحدد بين المدن ومواقع المشاريع."]'::jsonb, highlights_ar = '[{"title": "نقل من وإلى المطار وكبار الشخصيات", "description": "استقبال وتوصيل موثوق ونقل تنفيذي."}, {"title": "مركبات ميدانية وسائقون", "description": "مركبات وسائقون ذوو خبرة لزيارات المواقع والعمل الميداني."}, {"title": "التنقل بين المدن", "description": "تنسيق لوجستي آمن للسفر بين المدن والمناطق."}]'::jsonb where slug = 'internal-transportation';
update public.services set title_ar = 'دعم مركز الاتصال', description_ar = 'دعم هاتفي محلي عراقي، ومشغّلون ناطقون بالعربية، ومكالمات متابعة، وتنسيق للمواعيد.', body_ar = '["الاستجابة المستمرة للشركاء والعملاء وأصحاب المصلحة العراقيين تتطلب صوتًا محليًا. نقدّم دعم مركز اتصال ناطقًا بالعربية للتعامل مع الاستفسارات الواردة، ومكالمات المتابعة، وتنسيق المواعيد.", "تعمل فرقنا كامتداد لأعمالكم، فتحافظ على استمرارية التواصل أثناء عملكم عن بُعد أو بين الزيارات."]'::jsonb, highlights_ar = '[{"title": "مشغّلون ناطقون بالعربية", "description": "فرق محلية تتعامل مع المكالمات بالعربية والإنجليزية."}, {"title": "المتابعة وجدولة المواعيد", "description": "تنسيق المواعيد ومكالمات متابعة منظّمة."}, {"title": "التواصل الميداني", "description": "دعم تواصل فوري بين فريقكم وجهات الاتصال المحلية."}]'::jsonb where slug = 'call-center-support';
update public.services set title_ar = 'التوظيف المحلي والحر', description_ar = 'مترجمون فوريون، ومنسّقون، ومهندسون، ومساعدو مواقع، وفنيون — بعقود قصيرة أو طويلة الأمد.', body_ar = '["توسيع فريق العمل في العراق دون بنية تحتية محلية للتوظيف أمر بطيء ومحفوف بالمخاطر. نوفّر توظيفًا حرًا ومحليًا — مترجمين فوريين ومنسّقين ومهندسين ومساعدي مواقع وموظفي إدارة ومندوبي مبيعات وسائقين وفنيين.", "يُرتَّب التوظيف على أساس قصير أو طويل الأمد، بما يتناسب مع نطاق المشروع، لتتمكنوا من توسيع أو تقليص القدرة الميدانية حسب الحاجة."]'::jsonb, highlights_ar = '[{"title": "طاقم تقني وميداني", "description": "مهندسون ومساعدو مواقع وفنيون لتلبية احتياجات المشاريع."}, {"title": "مترجمون ومنسّقون", "description": "دعم لغوي وتنسيقي للاجتماعات والعمل الميداني."}, {"title": "شروط مرنة", "description": "توظيف قصير الأمد للمشاريع أو تعيينات أطول أمدًا."}]'::jsonb where slug = 'freelance-local-staffing';
update public.services set title_ar = 'تصديق العقود', description_ar = 'دعم تصديق العقود، وتنسيق المعاملات الحكومية، ومتابعة الوثائق التجارية.', body_ar = '["تصديق العقود ومستندات الشركات وتوثيقها بشكل صحيح في العراق يتطلب خطوات ومكاتب متعددة. ننسّق العملية نيابة عنكم، من خلال شركاء محليين موثوقين.", "هذا دعم توثيقي وتنسيقي — ويظل التصديق والموافقات خاضعين للقوانين العراقية المعمول بها ومتطلبات الجهات المختصة."]'::jsonb, highlights_ar = '[{"title": "دعم التصديق", "description": "تنسيق عبر شركاء محليين موثوقين لتصديق العقود."}, {"title": "متابعة المعاملات", "description": "تتبع ومتابعة الوثائق الحكومية والتجارية."}, {"title": "دعم مستندات الشركة", "description": "المساعدة في تنظيم وتقديم أوراق الشركة المطلوبة."}]'::jsonb where slug = 'contract-attestation';
update public.services set title_ar = 'التمثيل القانوني', description_ar = 'تنسيق التمثيل القانوني عبر شركاء قانونيين عراقيين موثوقين للعقود والمنازعات ومسائل الامتثال.', body_ar = '["بالنسبة للمسائل التي تتطلب تمثيلاً قانونيًا رسميًا في العراق، ننسّق مع شركاء قانونيين عراقيين موثوقين ومرخّصين نيابة عنكم.", "ندير العلاقة والتواصل بحيث يكون لمستشاركم القانوني في الخارج نقطة اتصال ميدانية موثوقة وسريعة الاستجابة، وذلك وفقًا للقوانين العراقية المعمول بها والأنظمة المهنية."]'::jsonb, highlights_ar = '[{"title": "شركاء قانونيون موثوقون", "description": "تنسيق مع ممارسين قانونيين عراقيين مرخّصين."}, {"title": "تنسيق التمثيل", "description": "تواصل ميداني للإجراءات القانونية والمعاملات."}, {"title": "تواصل مستمر", "description": "تحديثات منتظمة بين فريقكم والمستشار القانوني المحلي."}]'::jsonb where slug = 'legal-representation';
update public.services set title_ar = 'الاستشارات القانونية', description_ar = 'استشارات قانونية، ومراجعة العقود، وإرشاد تنظيمي، ودعم تأسيس الشركات عبر شركاء محليين موثوقين.', body_ar = '["فهم القانون التجاري العراقي والمتطلبات التنظيمية وإجراءات تأسيس الشركات أمر ضروري قبل الالتزام بالموارد. نربطكم بشركاء قانونيين عراقيين موثوقين للاستشارة والدعم الاستشاري.", "تشمل الخدمات مراجعة العقود، والإرشاد التنظيمي، ودعم تأسيس الشركات، والاستشارات المتعلقة بالامتثال المحلي — جميعها عبر شركاء قانونيين مرخّصين ووفقًا للقوانين العراقية المعمول بها."]'::jsonb, highlights_ar = '[{"title": "مراجعة العقود", "description": "مراجعة قانونية محلية للاتفاقيات قبل التوقيع."}, {"title": "دعم تأسيس الشركات", "description": "إرشاد خلال إجراءات تسجيل وهيكلة الشركات العراقية."}, {"title": "استشارات الامتثال", "description": "إرشاد تنظيمي مستمر بشأن الامتثال المحلي."}]'::jsonb where slug = 'legal-advisory';
update public.services set title_ar = 'توريد الأغذية والمشتريات', description_ar = 'توريد الأغذية للفرق والمخيمات والفعاليات، إضافة إلى مستلزمات المكاتب والمواقع والمشتريات التشغيلية اليومية.', body_ar = '["الحفاظ على تزويد الفرق والمخيمات ومواقع الفعاليات بالإمدادات يمثّل تحديًا تشغيليًا يوميًا في أسواق غير مألوفة. ندير توريد الأغذية ومستلزمات المكاتب والمشتريات الميدانية للفرق والعمال والوفود.", "من مكتب واحد إلى مخيم مشروع يمتد لأسابيع، نتولى التوريد والتسليم ليبقى فريقكم مزوَّدًا دون الحاجة لإدارة الموردين المحليين مباشرة."]'::jsonb, highlights_ar = '[{"title": "توريد الأغذية والتموين", "description": "توريد موثوق للفرق والمخيمات وتموين الفعاليات."}, {"title": "مستلزمات المكاتب والمواقع", "description": "توريد المواد التشغيلية اليومية."}, {"title": "لوجستيات يومية", "description": "دعم توريد مستمر للمهام الممتدة."}]'::jsonb where slug = 'food-supply-procurement';
update public.services set title_ar = 'إدارة الفعاليات', description_ar = 'فعاليات الأعمال، وورش العمل، والندوات، والوفود — حجز القاعات، والتموين، وإدارة الضيوف، والترجمة.', body_ar = '["استضافة فعالية أعمال أو ندوة تقنية أو زيارة وفد في العراق تتضمن عناصر عديدة متحركة. ننظّم الفعالية بالكامل — حجز القاعة، والتموين، وإدارة الضيوف، والترجمة، والنقل، وتنسيق الإعلام عند الحاجة.", "ندعم إطلاق المنتجات، واجتماعات التواصل، ومشاركات القطاعين الحكومي والخاص، من التخطيط وحتى التنفيذ."]'::jsonb, highlights_ar = '[{"title": "لوجستيات فعاليات متكاملة", "description": "إدارة القاعة والتموين والضيوف من البداية للنهاية."}, {"title": "برامج الوفود", "description": "برامج زيارة منظّمة للوفود التجارية والحكومية."}, {"title": "الترجمة والإعلام", "description": "ترجمة ميدانية وتنسيق إعلامي عند الحاجة."}]'::jsonb where slug = 'event-management';
update public.services set title_ar = 'التصاريح الأمنية', description_ar = 'دعم في التصاريح الأمنية، والوصول إلى المواقع، وموافقات التنقل، ومتطلبات التصريح المحلية.', body_ar = '["بعض المواقع والمناطق والأنشطة في العراق تتطلب تصاريح أو موافقات تنقل أو تنسيقًا رسميًا. ندعم الشركات في عملية التوثيق والتنسيق لهذه المتطلبات.", "هذا دعم ومساعدة في إجراءات التصاريح عبر شركاء محليين موثوقين — وتظل الموافقات خاضعة للقوانين العراقية المعمول بها وقرارات الجهات المختصة."]'::jsonb, highlights_ar = '[{"title": "مساعدة في إجراءات التصاريح", "description": "دعم في إعداد وتقديم الوثائق المطلوبة."}, {"title": "تنسيق الوصول إلى المواقع", "description": "دعم تنسيقي لمتطلبات الوصول إلى المواقع والمناطق."}, {"title": "موافقات التنقل", "description": "مساعدة في التعامل مع إجراءات تصريح التنقل."}]'::jsonb where slug = 'security-permits';
update public.services set title_ar = 'الترجمة القانونية', description_ar = 'ترجمة قانونية وتجارية وتقنية، إضافة إلى مترجمين فوريين للاجتماعات وزيارات المواقع والمفاوضات.', body_ar = '["الترجمة الدقيقة أمر بالغ الأهمية عندما تكون العقود والمستندات التقنية والمفاوضات على المحك. نقدّم ترجمة قانونية وتجارية وتقنية بين العربية والإنجليزية.", "كما يتوفر مترجمون فوريون للاجتماعات وزيارات المواقع والمفاوضات والفعاليات — لضمان عدم ضياع أي شيء في فجوة لغوية أو ثقافية."]'::jsonb, highlights_ar = '[{"title": "ترجمة قانونية وتجارية", "description": "ترجمة دقيقة للعقود والمستندات الرسمية."}, {"title": "ترجمة تقنية", "description": "ترجمة دقيقة للوثائق التقنية والهندسية."}, {"title": "مترجمون فوريون ميدانيون", "description": "ترجمة فورية للاجتماعات والمفاوضات وزيارات المواقع."}]'::jsonb where slug = 'legal-translation';
update public.services set title_ar = 'دعم العمليات الميدانية', description_ar = 'تنفيذ ميداني متكامل — كل ما تحتاجه شركة أجنبية في العراق، منسَّق عبر فريقنا وشبكتنا المحلية.', body_ar = '["بعض الاحتياجات لا تندرج بدقة تحت فئة واحدة. تعمل STRATIQ Access كنقطة تنسيق واحدة لكل ما يحتاجه فريقكم على الأرض في العراق.", "من خلال فريقنا المحلي وشبكة شركائنا الموثوقة، ننسّق التنفيذ عبر اللوجستيات والتوظيف والتوثيق والدعم الميداني — فيكون لديكم شريك واحد موثوق بدلاً من عشرات جهات الاتصال المحلية."]'::jsonb, highlights_ar = '[{"title": "نقطة اتصال واحدة", "description": "فريق محلي واحد ينسّق كل حاجة تشغيلية."}, {"title": "نطاق مرن", "description": "دعم يتناسب مع مشروعكم أو زيارتكم أو عملياتكم المستمرة."}, {"title": "شبكة موثوقة", "description": "تنفيذ مدعوم بشبكة مدقَّقة من الشركاء المحليين."}]'::jsonb where slug = 'field-operations-support';

update public.sectors set title_ar = 'الطاقة', description_ar = 'توليد الطاقة، وخدمات النفط والغاز، والمشاريع المتجددة التي تعيد تشكيل موازنة الطاقة في العراق.', body_ar = '["يقع قطاع الطاقة في العراق في صميم التوقعات الاقتصادية للبلاد، من توليد الطاقة وتحديث الشبكات إلى خدمات النفط والغاز ودفعة ناشئة نحو الطاقة المتجددة.", "نساعد شركات الطاقة وموردي المعدات على فهم مكامن الفرصة الحقيقية — الجهات التي تتحكم بالميزانيات، والمناقصات التنافسية فعليًا، والشراكات التي تجعل العرض التنافسي ذا مصداقية لا مجرد استيفاء للشروط."]'::jsonb, highlights_ar = '[{"title": "الدخول إلى الشبكة والتوليد", "description": "رسم خريطة الجهات المسؤولة عن مشاريع التوليد والنقل، ومسار الموافقة لموردي المعدات والمقاولين الأجانب."}, {"title": "تموضع المشاريع المتجددة", "description": "تحديد أين تكون مبادرات الطاقة الشمسية والريحية ممولة وقيد التنفيذ فعليًا، لا مجرد معلنة."}, {"title": "الوصول إلى خدمات النفط والغاز", "description": "هيكلة التمثيل المحلي والشراكات للشركات المورّدة لخدمات القطاعين الأعلى والأوسط."}]'::jsonb where slug = 'energy';
update public.sectors set title_ar = 'البنية التحتية', description_ar = 'برامج النقل والمياه والأشغال العامة المدعومة بخطط تنمية وطنية طويلة الأمد.', body_ar = '["تواصل خطط التنمية الوطنية توجيه استثمارات كبيرة نحو الطرق وأنظمة المياه والأشغال العامة عبر محافظات العراق، ويُموَّل جزء كبير منها عبر مزيج من الموازنة الحكومية والدعم الدولي.", "نساعد شركات البنية التحتية على تتبع البرامج الممولة والفعّالة، وفهم سلاسل الموافقة الحكومية والمانحة خلفها، والتموضع قبل الإعلانات الرسمية عن المناقصات."]'::jsonb, highlights_ar = '[{"title": "رسم خريطة البرامج", "description": "تتبع برامج البنية التحتية النشطة والمخطَّطة عبر الجهات المحلية والوطنية."}, {"title": "الوصول إلى المشاريع الممولة دوليًا", "description": "فهم كيفية اختيار وتأهيل المقاولين في برامج إعادة الإعمار الممولة دوليًا."}, {"title": "مناقصات الأشغال العامة", "description": "إعداد ملفات تأهيل تلبي معايير التوثيق التي تتطلبها الجهات المحلية تحديدًا."}]'::jsonb where slug = 'infrastructure';
update public.sectors set title_ar = 'الإنشاءات', description_ar = 'أنشطة إعادة الإعمار والبناء الجديد عبر المشاريع السكنية والتجارية والحكومية.', body_ar = '["يتواصل نشاط إعادة الإعمار والبناء الجديد عبر المشاريع السكنية والتجارية والحكومية، مع تجاوز الطلب على المواد والمقاولين وخدمات البناء المتخصصة للعرض المحلي في عدة فئات.", "نعمل مع شركات الإنشاءات وموردي المواد لتحديد خطوط المشاريع النشطة، وتأهيل الشركاء المحليين، والتعامل مع متطلبات التراخيص والعمالة الخاصة بمواقع البناء العراقية."]'::jsonb, highlights_ar = '[{"title": "تتبع خط المشاريع", "description": "مراقبة المشاريع السكنية والتجارية والحكومية من التخطيط وحتى المناقصة."}, {"title": "تدقيق المقاولين المحليين", "description": "تحديد وفحص المقاولين المحليين وموردي المواد للمشاريع المشتركة أو التعاقد من الباطن."}, {"title": "متطلبات تشغيل المواقع", "description": "إرشاد بشأن معايير التراخيص والعمالة والسلامة الخاصة بأعمال البناء في العراق."}]'::jsonb where slug = 'construction';
update public.sectors set title_ar = 'الرعاية الصحية', description_ar = 'تطوير المستشفيات، والمعدات الطبية، وخدمات الرعاية الصحية المتوسعة عبر المحافظات.', body_ar = '["يتوسع الاستثمار الحكومي في تطوير المستشفيات وخدمات الرعاية الصحية عبر بغداد والمحافظات، ما يخلق طلبًا مستدامًا على المعدات الطبية والأدوية وخدمات الرعاية الصحية المتخصصة.", "نساعد موردي ومشغّلي الرعاية الصحية على فهم عمليات الشراء عبر المستشفيات الحكومية ووزارة الصحة، والتواصل مع الموزعين والممثلين المحليين اللازمين للعمل بما يتوافق مع الأنظمة."]'::jsonb, highlights_ar = '[{"title": "المشتريات الصحية العامة", "description": "فهم آلية شراء المعدات والأدوية عبر وزارة الصحة والجهات الصحية المحلية."}, {"title": "توزيع المعدات الطبية", "description": "تحديد موزعين محليين مؤهلين وشركاء خدمة ما بعد البيع لموردي المعدات الطبية."}, {"title": "شراكات المرافق الصحية", "description": "هيكلة التواصل مع مشغّلي المستشفيات الخاصة والعامة الساعية للتوسع."}]'::jsonb where slug = 'healthcare';
update public.sectors set title_ar = 'تقنية المعلومات والتحول الرقمي', description_ar = 'التحول الرقمي الحكومي، والبنية التحتية للاتصالات، وتبني التقنية في قطاع الأعمال.', body_ar = '["تخلق برامج التحول الرقمي الحكومية، وتحديث البنية التحتية للاتصالات، وتنامي تبني تقنية الأعمال، قناة مستمرة من فرص تقنية المعلومات عبر القطاعين العام والخاص.", "نساعد شركات التقنية ومتكاملي الأنظمة على فهم آلية عمل مشتريات تقنية المعلومات الحكومية فعليًا، ونربطهم بالشركاء المحليين اللازمين لتنفيذ ودعم عمليات التطبيق ميدانيًا."]'::jsonb, highlights_ar = '[{"title": "الوصول إلى برامج الحكومة الإلكترونية", "description": "رسم خريطة الوزارات والجهات العامة التي تدير مبادرات التحول الرقمي والحكومة الإلكترونية."}, {"title": "شراكات تكامل الأنظمة", "description": "تحديد متكاملي أنظمة محليين قادرين على دعم التنفيذ وخدمة ما بعد البيع."}, {"title": "دخول البنية التحتية للاتصالات", "description": "تموضع موردي المعدات والبنية التحتية أمام برامج توسع الاتصالات النشطة."}]'::jsonb where slug = 'ict';
update public.sectors set title_ar = 'الأمن ودعم الدفاع', description_ar = 'خدمات الدعم، والمعدات، وبرامج التدريب لمتطلبات الأمن العام والخاص.', body_ar = '["يخلق التحديث المستمر لقدرات الأمن العام والخاص فرصًا لخدمات الدعم المؤهلة، وموردي المعدات، ومقدّمي التدريب القادرين على تلبية متطلبات الامتثال والتدقيق الصارمة.", "نساعد الشركات في هذا القطاع على التعامل مع العلاقات الحكومية الخاصة وإجراءات التصاريح المرتبطة به، لضمان بناء التعامل بشكل صحيح منذ البداية."]'::jsonb, highlights_ar = '[{"title": "التعامل مع الامتثال والتدقيق", "description": "إرشاد بشأن متطلبات التصريح والامتثال الخاصة بالتعامل مع قطاع الأمن في العراق."}, {"title": "المعدات وخدمات الدعم", "description": "تموضع موردي معدات الأمن وخدمات الدعم أمام القنوات الحكومية المؤهلة."}, {"title": "شراكات برامج التدريب", "description": "هيكلة شراكات محلية للشركات المقدّمة لبرامج التدريب وبناء القدرات."}]'::jsonb where slug = 'security';
update public.sectors set title_ar = 'اللوجستيات وسلسلة التوريد', description_ar = 'الشحن، والتخزين، والممرات التجارية التي تربط العراق بسلاسل التوريد الإقليمية والعالمية.', body_ar = '["يدفع موقع العراق كممر تجاري إقليمي نموًا مستدامًا في الشحن والتخزين وبنية التوزيع، ويربط البلاد بسلاسل توريد إقليمية وعالمية أوسع.", "نساعد شركات اللوجستيات وسلاسل التوريد على رسم خريطة شبكات التوزيع المحافظية، والمعابر الحدودية، وطاقة التخزين ذات الصلة بعملياتها، وبناء شراكات محلية مصممة للمدى الطويل."]'::jsonb, highlights_ar = '[{"title": "تصميم شبكة التوزيع", "description": "هيكلة نماذج توزيع متعددة المحافظات متوازنة مع تكاليف لوجستية واقعية."}, {"title": "الوصول إلى الحدود والممرات التجارية", "description": "فهم المعابر الحدودية والممرات التجارية الأكثر صلة بسلسلة توريد معينة."}, {"title": "تحديد شركاء التخزين", "description": "تحديد وتدقيق شركاء تخزين وشحن محليين عبر المحافظات ذات الأولوية."}]'::jsonb where slug = 'logistics';
update public.sectors set title_ar = 'السلع الاستهلاكية والصناعية', description_ar = 'التصنيع، والسلع الاستهلاكية سريعة الدوران، والتوريد الصناعي لخدمة قاعدة العراق الاستهلاكية والصناعية المتنامية.', body_ar = '["تدفع قاعدة العراق الاستهلاكية والصناعية المتنامية الطلب عبر التصنيع والسلع الاستهلاكية سريعة الدوران والتوريد الصناعي، مع بقاء علاقات التوزيع المحلية العامل الأساسي الفاصل بين حصة سوقية مستدامة ودفعة مبيعات قصيرة الأمد.", "نساعد شركات السلع الاستهلاكية والصناعية على تحديد وتدقيق شركاء التوزيع المحليين، وهيكلة اتفاقيات مبنية على حوافز مشتركة طويلة الأمد لا على دورة شحنة واحدة."]'::jsonb, highlights_ar = '[{"title": "تحديد الموزعين", "description": "تحديد وفحص شركاء توزيع محليين وفق القدرة التجارية والوضع الامتثالي."}, {"title": "رسم خريطة قنوات التجزئة والتجارة", "description": "فهم قنوات التجزئة والتجارة الأكثر صلة بفئة منتج معينة عبر المحافظات."}, {"title": "هيكلة الشراكات طويلة الأمد", "description": "التفاوض على شروط توزيع مصممة لإبقاء الشركاء ملتزمين لما بعد الطلبية الأولى."}]'::jsonb where slug = 'consumer-industrial';

update public.case_studies set title_ar = 'استراتيجية دخول السوق لشركة تقنية دولية', sector_ar = 'تقنية المعلومات والتحول الرقمي', summary_ar = 'صممنا خطة دخول متدرجة شملت التأسيس التنظيمي، ورسم خريطة أصحاب المصلحة الحكوميين، والأهداف التجارية الأولية.', body_ar = '["احتاجت شركة تقنية تستعد لدخول العراق إلى رؤية واقعية للخطوات التنظيمية، ومتطلبات الترخيص المحلي، والجهات الحكومية التي يجب التعامل معها قبل أن تتمكن من العمل.", "بنينا خطة دخول متدرجة رتّبت التأسيس القانوني، والتسجيل المحلي، وبناء العلاقات الحكومية إلى جانب قائمة أهداف تجارية أولية، بحيث كانت للأشهر الاثني عشر الأولى معالم واضحة وقابلة للتحقيق بدلاً من بحث مفتوح.", "استمر التعاون حتى أول توظيف محلي للشركة وأولى اجتماعاتها مع الجهات الحكومية، مع توفير فريقنا للاستمرارية عبر كل مرحلة."]'::jsonb where slug = 'tech-market-entry';
update public.case_studies set title_ar = 'رسم خريطة المناقصات لمشاريع البنية التحتية للطاقة', sector_ar = 'الطاقة', summary_ar = 'بنينا خط مناقصات حيًا عبر جهات الطاقة الوطنية والمحافظية، مرتَّبًا حسب الملاءمة واحتمالية الفوز.', body_ar = '["احتاج مورّد معدات طاقة دولي إلى رؤية مستمرة للمناقصات المقبلة عبر الجهات الوطنية والمحافظية، بدلاً من الاعتماد على معلومات عرضية بعد فوات الأوان.", "بنينا خط مناقصات محدَّثًا باستمرار يغطي الفئات التقنية ذات الأولوية للعميل، وقيَّمنا كل فرصة وفق قدرة العميل الفعلية وأنماط فوزه السابقة، وأشرنا إلى أقوى التطابقات قبل المواعيد النهائية العلنية.", "كانت النتيجة قائمة مختصرة يمكن للعميل التصرف بناءً عليها بوقت كافٍ، بدلاً من التسرع لإعداد عرض في الأسابيع الأخيرة قبل التقديم."]'::jsonb where slug = 'energy-tender-mapping';
update public.case_studies set title_ar = 'تحديد شريك محلي للتوريد الصناعي', sector_ar = 'السلع الاستهلاكية والصناعية', summary_ar = 'حدّدنا ودقّقنا شركاء توزيع محليين، ورتّبنا المرشحين وفق معايير تجارية وامتثالية.', body_ar = '["أراد مورّد صناعي دخول السوق العراقي عبر شريك توزيع محلي، لكن لم يكن لديه وسيلة موثوقة لتحديد أو تقييم المرشحين من خارج البلاد.", "حدّدنا مجموعة من الموزعين المحتملين، ثم فحصناهم وفق القدرة التجارية والعلاقات القطاعية القائمة والوضع الامتثالي، وضيّقنا المجال إلى قائمة مختصرة تمكّن العميل من الدخول بثقة في مفاوضات مباشرة.", "بقينا متواجدين خلال عملية التفاوض للمساعدة في صياغة شروط تحمي مصالح العميل طويلة الأمد، لا الاتفاقية الأولية فقط."]'::jsonb where slug = 'industrial-partner-search';
update public.case_studies set title_ar = 'تمثيل استراتيجي للفرص الموجّهة نحو الجهات الحكومية', sector_ar = 'الحكومة والقطاع العام', summary_ar = 'قدّمنا تمثيلاً محليًا مستمرًا لإبقاء فرصة حكومية متعددة السنوات متوافقة عبر مراحل الموافقة.', body_ar = '["تطلّبت فرصة حكومية متعددة السنوات تعاملاً محليًا مستمرًا عبر عدة مراحل موافقة — وهو أمر لم يستطع فريق العميل الدولي الحفاظ عليه بمفرده.", "قدّمنا تمثيلاً محليًا مستمرًا، حافظ على توافق الفرصة مع الجهات العامة المعنية أثناء مرورها بكل مرحلة، وأبرزنا المشكلات مبكرًا بما يكفي ليتمكن العميل من الاستجابة قبل أن تتحول إلى تأخيرات.", "كان هذا الحضور المحلي المستمر هو الفارق بين مشروع توقف عند أول عقبة إجرائية ومشروع واصل التقدم."]'::jsonb where slug = 'government-facing-representation';
update public.case_studies set title_ar = 'دراسة جدوى لتوسعة البنية التحتية', sector_ar = 'البنية التحتية', summary_ar = 'قدّمنا تقييمًا للطلب والمخاطر دعم قرارًا على مستوى مجلس الإدارة بشأن توسعة إقليمية للبنية التحتية.', body_ar = '["قبل قرار تخصيص رأسمال على مستوى مجلس الإدارة، احتاج مستثمر في البنية التحتية إلى رؤية مستقلة ومدعومة بالبيانات للطلب الإقليمي والمخاطر الخاصة بالسوق العراقي.", "قدّمنا دراسة جدوى جمعت بين نمذجة الطلب، وتقييم المخاطر التنظيمية، والتحقق الميداني من افتراضات كانت مبنية أصلاً على بحث مكتبي فقط.", "منحت الدراسة مجلس الإدارة أساسًا واضحًا لقراره، بما في ذلك عوامل المخاطر التي تتطلب إدارة فعّالة بدلاً من أن تُترك كملاحظات هامشية."]'::jsonb where slug = 'infrastructure-feasibility';
update public.case_studies set title_ar = 'نموذج توزيع لنمو السوق العراقي', sector_ar = 'اللوجستيات وسلسلة التوريد', summary_ar = 'هيكلنا نموذج توزيع متعدد المحافظات يوازن بين التغطية والتكلفة وحوافز الشركاء طويلة الأمد.', body_ar = '["أرادت شركة سلع استهلاكية لديها موطئ قدم أولي في بغداد توسيع التوزيع إلى محافظات إضافية دون الإفراط في تكاليف اللوجستيات أو فقدان السيطرة على جودة الخدمة.", "هيكلنا نموذج توزيع يوازن بين التغطية المحافظية وتكاليف لوجستية واقعية، وأدرجنا هياكل حوافز مصممة لإبقاء الشركاء المحافظيين ملتزمين على المدى الطويل لا لدورة الشحنة الأولى فقط.", "منح النموذج العميل مسار توسع واضحًا ومتسلسلاً بدلاً من طرح شامل دفعة واحدة لم يكن مهيّأً لدعمه."]'::jsonb where slug = 'distribution-model';

update public.insights set title_ar = 'المشهد المناقصاتي في العراق: كيف يمكن للشركات الدولية المنافسة', excerpt_ar = 'نظرة عملية على آلية عمل المشتريات الحكومية في العراق، وما يحتاجه المزايدون المؤهلون قبل المنافسة.', body_ar = '["تجري المشتريات الحكومية في العراق عبر مزيج من الوزارات الاتحادية والجهات المحافظية والشركات المملوكة للدولة، ولكل منها تقويمها الخاص بالمناقصات ومتطلبات التوثيق.", "الشركات التي تنافس بنجاح تتعامل مع متابعة المناقصات كانضباط مستمر لا بحثًا لمرة واحدة — إذ تتغير معايير التأهيل، ومتطلبات الشركاء المحليين، ومواعيد التقديم بوتيرة كافية لجعل أي رؤية ثابتة للسوق تتقادم بسرعة.", "الحضور المحلي المنظّم، سواء بشكل مباشر أو عبر ممثل، يبقى العامل الأكبر الفاصل بين المزايدين الذين يصلون إلى القائمة المختصرة وأولئك الذين لا يصلون."]'::jsonb where slug = 'tender-landscape';
update public.insights set title_ar = 'فرص الطاقة والبنية التحتية في العراق', excerpt_ar = 'أين يخلق توليد الطاقة، وتحديث الشبكات، وتمويل البنية التحتية مجالاً للمشغّلين الدوليين.', body_ar = '["تبقى بنية توليد الطاقة والشبكات في العراق تحت ضغط استثماري مستمر، مع استهداف برامج وطنية لتوسعة القدرة وتحديث النقل في آن واحد.", "يواصل موردو المعدات الدوليون ومقاولو التنفيذ إيجاد مجال للمنافسة، خاصة حيث يمكنهم الجمع بين القدرة التقنية وشريك تنفيذ محلي ذي مصداقية.", "تتضمن هياكل تمويل برامج البنية التحتية الكبرى بشكل متزايد مزيجًا من الموازنة العامة والدعم متعدد الأطراف ورأس المال الخاص — وفهم أي منها ينطبق على مشروع معين يغيّر طريقة التعامل معه."]'::jsonb where slug = 'energy-infrastructure-opportunities';
update public.insights set title_ar = 'التحول الرقمي وخدمات الحكومة الذكية', excerpt_ar = 'كيف تعيد برامج التحول الرقمي الحكومي تشكيل المشتريات وتفتح قنوات جديدة لشركاء التقنية.', body_ar = '["ينتقل التحول الرقمي الحكومي من مشاريع تجريبية إلى برامج مستدامة عبر عدة وزارات، تغطي كل شيء من خدمات المواطنين إلى أنظمة إدارة الحالات الداخلية.", "يخلق هذا التحول قناة مستمرة من مناقصات تقنية المعلومات التي تكافئ الموردين القادرين على إثبات كل من التنفيذ التقني وفهم آلية عمل المشتريات الحكومية عمليًا.", "الشراكة مع متكامل أنظمة أو ممثل محلي غالبًا ما تكون الفارق بين عرض قوي تقنيًا وعرض متموضع فعليًا للفوز."]'::jsonb where slug = 'digital-transformation-smart-government';
update public.insights set title_ar = 'بناء شراكات محلية للنجاح طويل الأمد', excerpt_ar = 'ما الذي يميّز الشراكة المحلية الدائمة عن الترتيب قصير الأمد، وكيف تُبنى الاستراتيجية على المدى البعيد.', body_ar = '["أكثر الشراكات المحلية ديمومة في العراق هي تلك المبنية على حوافز تجارية مشتركة، لا مجرد اتفاقية توزيع موقّعة.", "تدقيق الشريك المحتمل يتجاوز الوضع المالي — فسجل التعامل مع الجهات الحكومية، والعلاقات القطاعية القائمة، والقدرة التشغيلية، كلها تهم بقدر أهمية قوة الميزانية.", "الشركات التي تتعامل مع اختيار الشريك كقرار استراتيجي، لا كإجراء شكلي لفتح الوصول إلى السوق، تحقق باستمرار نتائج أقوى على المدى الطويل."]'::jsonb where slug = 'building-local-partnerships';
